package ru.memearena.battle.api; import io.swagger.v3.oas.annotations.Operation; import org.springframework.http.*; import org.springframework.security.core.annotation.AuthenticationPrincipal; import org.springframework.web.bind.annotation.*; import ru.memearena.battle.application.BattleService; import ru.memearena.security.AuthenticatedUserPrincipal; import java.util.UUID; @RestController @RequestMapping("/api/v1/battles") public class BattleController { private final BattleService service; public BattleController(BattleService service){this.service=service;} @GetMapping("/next") @Operation(summary="Get next battle") public ResponseEntity<NextBattleResponse> next(@AuthenticationPrincipal AuthenticatedUserPrincipal p,@Deprecated @RequestParam(required=false) UUID userId){return service.next(p.userId()).map(ResponseEntity::ok).orElseGet(()->ResponseEntity.noContent().build());} }
